class Solution {
public:
    int integerReplacement(int n) {
        long long num = n;
        int operations = 0;
        while (num != 1) {
            if (num % 2 == 0) {
                num /= 2;
            } else if (num % 4 == 1 || num == 3) {
                num -= 1;
            } else {
                num += 1;
            }
            operations++;
        }
        return operations;
    }
};
```
